sp_widget.client_script:
api.controller=function($scope, spUtil,$location,spModal) {
  /* widget controller */
  var c = this;
	c.data=c.data||{};

		$scope.$on('openFiscalPeriods', function(event, data) {

			var sys_id = data.sys_id;
			spUtil.get("incentnow-fiscal-period-nd", {   
				calendar_sys_id: sys_id,
				table: "x_ctans_incentnow_fiscal_period"
			}).then(function(response) {

				c.periodWidget = response;
				setTimeout(function() {
				var el = document.getElementById("fiscalPeriodSection");
				if (el) {
					el.scrollIntoView({ behavior: "smooth", block: "start" });
				}
				}, 100);

			});

			});



	c.createFiscalCalendar = function() {

		sessionStorage.setItem('prevPage', $location.absUrl());
  $location.url("?id=incentnow_form&table="+'x_ctans_incentnow_fiscal_calendar'+"&sys_id=-1");
};


	c.openModal=function(){

		spModal.open({
				title: 'Fiscal Calendar',
				widget: 'incentnow-modal-of-form',
				widgetInput: {
					sys_id: '0bb7c9563b3b36d0ffa00e9693e45af8',
					table: 'x_ctans_incentnow_fiscal_calendar',
					view: 'portal_view'
				}
			});
	}
};

sp_widget.css:
.fiscal-btn {
  background-color: #050521; /* dark navy */
  color: #ffffff;
  border: none;
  border-radius: 10px;
  padding: 10px 20px;
  font-size: 16px;
  display: inline-flex;
  align-items: center;
  gap: 10px;
  cursor: pointer;
  transition: all 0.2s ease;

}

.fiscal-btn .icon {
  font-size: 20px;
  font-weight: bold;
}

.fiscal-btn:hover {
  background-color: #0a0a3a;
}

.btn-container {
  text-align: right;
  margin-bottom:5px;
}

sp_widget.script:
(function() {
  /* populate the 'data' object */
  /* e.g., data.table = $sp.getValue('table'); */
	data.fiscalCalendar   = $sp.getWidget('incentnow-table-widget',{ table: 'x_ctans_incentnow_fiscal_calendar',view:'default view',viewperiod:'true'});
	data.reportWidget=$sp.getWidget('incentnow-fiscal-report');


})();
